const option = (id, text) => ({ id, text });
const q = (id, domain, type, prompt, options, correct, explanation, objective, caseStudy) => ({
  id, domain, type, prompt, options, correct, explanation, objective, ...(caseStudy ? { caseStudy } : {})
});
const h = (...args) => ({ ...q(...args), difficulty: "hardcore-legacy" });
const x = (...args) => ({ ...q(...args), difficulty: "hardcore" });

